/**data:image/png;base64,
 * Avatar Elin (Base64) — ใช้แทนโฟลเดอร์ img
 * ใส่สาย base64 ของรูปใน AVATAR_BASE64 ด้านล่าง (ไม่รวม "data:image/png;base64,")
 */
(function(global) {
  var AVATAR_BASE64 = 'PASTE_YOUR_BASE64_STRING_HERE';

  if (typeof AVATAR_BASE64 !== 'string' || AVATAR_BASE64 === 'PASTE_YOUR_BASE64_STRING_HERE') {
    AVATAR_BASE64 = '';
  }

  var dataUrl = AVATAR_BASE64
    ? (AVATAR_BASE64.indexOf('data:') === 0 ? AVATAR_BASE64 : 'data:image/png;base64,' + AVATAR_BASE64)
    : '';

  var cssUrl = AVATAR_BASE64
    ? (AVATAR_BASE64.indexOf('url(') === 0 ? AVATAR_BASE64 : 'url(data:image/png;base64,' + AVATAR_BASE64 + ')')
    : '';

  global.SOMR_AVATAR_IMG = dataUrl;
  global.SOMR_AVATAR_CSS = cssUrl;
})(typeof window !== 'undefined' ? window : this);
